$historyPath = "$env:APPDATA\Code\User\History"; $results = @(); Get-ChildItem -Path $historyPath -Recurse -Filter "entries.json" | ForEach-Object { $content = Get-Content $_.FullName | ConvertFrom-Json; $resource = $content.resource; if ($resource -match "BentoGridSection.tsx|BentoGridIntro.tsx|BentoGrid.tsx|AboutOregent.tsx") { foreach ($entry in $content.entries) { $results += [PSCustomObject]@{ Resource = $resource; Path = "$($_.DirectoryName)\$($entry.id)"; Timestamp = $entry.timestamp; Date = (Get-Date -Date "1970-01-01 00:00:00Z").AddMilliseconds($entry.timestamp).ToLocalTime() } } } }; $results | Sort-Object Timestamp -Descending | Export-Csv -Path "d:\OREHACK\history_entries.csv" -NoTypeInformation
